import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import datasets, transforms, models
from torch.utils.data import DataLoader
import requests
import os

def download_model(url, download_path):
    response = requests.get(url)
    with open(download_path, 'wb') as f:
        f.write(response.content)

def load_model(file_path):
    state_dict = torch.load(file_path, map_location=torch.device('cpu'))
    model = models.__dict__[state_dict['arch']]()
    model.load_state_dict(state_dict['state_dict'])
    return model

def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.SGD(model.parameters(), lr=learning_rate, momentum=0.9)

    model.train()
    for epoch in range(num_epochs):
        running_loss = 0.0
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader):.4f}')

def prepare_data(train_dir, batch_size=32):
    train_transforms = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
    ])
    train_dataset = datasets.ImageFolder(train_dir, transform=train_transforms)
    train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True)
    return train_loader

if __name__ == '__main__':
    url = 'https://path_to_pretrained_model/model.pth'
    model_path = 'downloaded_model.pth'
    
    # Download the model from URL
    download_model(url, model_path)

    # Load the model checkpoint
    model = load_model(model_path)

    # Prepare custom dataset
    train_loader = prepare_data('path_to_custom_dataset')

    # Fine-tune the downloaded model
    fine_tune_model(model, train_loader)